def center_crop_to_target_aspect_ratio(
    image: torch.Tensor,
    target_height: int,
    target_width: int
) -> torch.Tensor:
    """
    Center crop an image to the target aspect ratio.

    Args:
        image: input image tensor of shape [C, H, W] or [B, C, H, W]
        target_height: target height
        target_width: target width

    Returns:
        the cropped image tensor
    """

    # Get the current image size
    if len(image.shape) == 3:
        # [C, H, W]
        _, curr_h, curr_w = image.shape
        batch_dim = False
    elif len(image.shape) == 4:
        # [B, C, H, W]
        _, _, curr_h, curr_w = image.shape
        batch_dim = True
    else:
        raise ValueError(
            f"Unsupported image dimensions: {image.shape}, only 3D [C,H,W] or 4D [B,C,H,W] are supported"
        )

    # Compute aspect ratios
    target_ratio = target_width / target_height
    curr_ratio = curr_w / curr_h

    # Initialize crop parameters
    crop_h = curr_h
    crop_w = curr_w
    y_offset = 0
    x_offset = 0

    if curr_ratio > target_ratio:
        # Image too wide -> crop the width
        crop_w = int(curr_h * target_ratio)
        x_offset = (curr_w - crop_w) // 2

    elif curr_ratio < target_ratio:
        # Image too tall -> crop the height
        crop_h = int(curr_w / target_ratio)
        y_offset = (curr_h - crop_h) // 2

    else:
        return image

    # Perform the crop
    if batch_dim:
        cropped = image[
            :,
            :,
            y_offset:y_offset + crop_h,
            x_offset:x_offset + crop_w
        ]
    else:
        cropped = image[
            :,
            y_offset:y_offset + crop_h,
            x_offset:x_offset + crop_w
        ]

    return cropped
def center_crop_tensor(
    image: torch.Tensor,
    target_height: int,
    target_width: int
) -> torch.Tensor:
    """
    Resize then center crop the image so the output matches the target size.

    Args:
        image: input image tensor of shape [C, H, W] or [B, C, H, W]
        target_height: target height
        target_width: target width

    Returns:
        the center-cropped image tensor
    """

    # Determine whether there is a batch dimension
    if image.dim() == 3:
        # [C, H, W] -> [1, C, H, W]
        image = image.unsqueeze(0)
        batch_dim = False
    elif image.dim() == 4:
        batch_dim = True
    else:
        raise ValueError(
            f"Unsupported image dimensions: {image.shape}, only 3D [C,H,W] or 4D [B,C,H,W] are supported"
        )

    B, C, H, W = image.shape

    target_size = min(target_height, target_width)

    # --------------------------------------------------
    # Step 1: mimic ADM progressive downsample
    # --------------------------------------------------
    while min(H, W) >= 2 * target_size:
        image = F.interpolate(
            image,
            scale_factor=0.5,
            mode="area"
        )
        H, W = image.shape[-2:]

    # --------------------------------------------------
    # Step 2: scale so min side == target_size
    # --------------------------------------------------
    scale = target_size / min(H, W)

    new_h = round(H * scale)
    new_w = round(W * scale)

    image = F.interpolate(
        image,
        size=(new_h, new_w),
        mode="bicubic",
        align_corners=False
    )

    # --------------------------------------------------
    # Step 3: center crop
    # --------------------------------------------------
    crop_y = (new_h - target_height) // 2
    crop_x = (new_w - target_width) // 2

    image = image[:, :, crop_y:crop_y + target_height, crop_x:crop_x + target_width]

    if not batch_dim:
        image = image.squeeze(0)

    return image


def pad_to_aspect_ratio(
    image: torch.Tensor,
    target_height: int,
    target_width: int,
    pad_value: float = 0.0
) -> torch.Tensor:
    """
    Pad the image to the target aspect ratio, avoiding stretching distortion on resize.

    Args:
        image: input image tensor of shape [C, H, W] or [B, C, H, W]
        target_height: target height
        target_width: target width
        pad_value: padding fill value, defaults to 0

    Returns:
        the padded image tensor; the original content is preserved and only the edges are padded
    """
    # Get the current image size
    if len(image.shape) == 3:
        # [C, H, W]
        _, curr_h, curr_w = image.shape
        batch_dim = False
    elif len(image.shape) == 4:
        # [B, C, H, W]
        _, _, curr_h, curr_w = image.shape
        batch_dim = True
    else:
        raise ValueError(f"Unsupported image dimensions: {image.shape}, only 3D [C,H,W] or 4D [B,C,H,W] are supported")

    # Compute target and current aspect ratios
    target_ratio = target_width / target_height
    curr_ratio = curr_w / curr_h

    # Compute the required padding size
    if curr_ratio < target_ratio:
        # Pad along the width
        new_w = int(curr_h * target_ratio)
        pad_w = new_w - curr_w
        pad_left = pad_w // 2
        pad_right = pad_w - pad_left
        pad_top, pad_bottom = 0, 0
    else:
        # Pad along the height
        new_h = int(curr_w / target_ratio)
        pad_h = new_h - curr_h
        pad_top = pad_h // 2
        pad_bottom = pad_h - pad_top
        pad_left, pad_right = 0, 0

    # Build the padding argument (left, right, top, bottom)
    padding = (pad_left, pad_right, pad_top, pad_bottom)

    # Apply padding
    # F.pad padding argument order: (left, right, top, bottom, front, back)
    padded_image = F.pad(image, padding, mode='constant', value=pad_value)

    return padded_image


